CountSortFrequency MapForeachLoop <p>Uses <code>count_chars()</code>, a single native C call. No helper needed. <pre><code>&lt;?php

    public static function viaCount(string $word1, string $word2): bool
    {
        $a = self::clean($word1);
        $b = self::clean($word2);

        if (\strlen($a) !== \strlen($b)) {
            return false;
        }

        return \count_chars($a, 1) === \count_chars($b, 1);
    }
</code></pre></p> <p>Split into characters, sort, and compare as strings. <pre><code>&lt;?php

    public static function viaSort(string $word1, string $word2): bool
    {
        $a = self::clean($word1);
        $b = self::clean($word2);

        if (\strlen($a) !== \strlen($b)) {
            return false;
        }

        return self::sorted($a) === self::sorted($b);
    }

    private static function sorted(string $str): string
    {
        $chars = mb_str_split($str);
        sort($chars);
        return \implode('', $chars);
    }
</code></pre></p> <p>Build a frequency table using <code>array_map</code> and compare. <pre><code>&lt;?php

    public static function viaFreq(string $word1, string $word2): bool
    {
        $a = self::clean($word1);
        $b = self::clean($word2);

        if (\strlen($a) !== \strlen($b)) {
            return false;
        }

        return self::freqMap($a) === self::freqMap($b);
    }

    /**
     * @return array&lt;string, int&gt;
     */
    private static function freqMap(string $str): array
    {
        $freq = [];
        \array_map(function ($char) use (&amp;$freq) {
            $freq[$char] = ($freq[$char] ?? 0) + 1;
        }, mb_str_split($str));
        \ksort($freq);
        return $freq;
    }
</code></pre></p> <p>Same as Frequency Map, using <code>foreach</code> instead of <code>array_map</code>. <pre><code>&lt;?php

    public static function viaForeach(string $word1, string $word2): bool
    {
        $a = self::clean($word1);
        $b = self::clean($word2);

        if (\strlen($a) !== \strlen($b)) {
            return false;
        }

        return self::foreachMap($a) === self::foreachMap($b);
    }

    /**
     * @return array&lt;string, int&gt;
     */
    private static function foreachMap(string $str): array
    {
        $freq = [];
        foreach (mb_str_split($str) as $char) {
            $freq[$char] = ($freq[$char] ?? 0) + 1;
        }
        \ksort($freq);
        return $freq;
    }
</code></pre></p> <p>Builds the frequency table with a <code>for</code> loop, then compares key by key. <pre><code>&lt;?php

    public static function viaLoop(string $word1, string $word2): bool
    {
        $a = self::clean($word1);
        $b = self::clean($word2);

        if (\strlen($a) !== \strlen($b)) {
            return false;
        }

        $freq1 = self::loopMap($a);
        $freq2 = self::loopMap($b);

        foreach ($freq1 as $char =&gt; $count) {
            if (!isset($freq2[$char]) || $freq2[$char] !== $count) {
                return false;
            }
        }

        return true;
    }

    /**
     * @return array&lt;string, int&gt;
     */
    private static function loopMap(string $str): array
    {
        $length = \strlen($str);
        $freq   = [];
        for ($i = 0; $i &lt; $length; $i++) {
            $char        = $str[$i];
            $freq[$char] = ($freq[$char] ?? 0) + 1;
        }
        return $freq;
    }
</code></pre></p>

