public static function printFizzBuzz(int $number): string
{
    $str = '';

    for ($i = 1; $i &lt;= $number; $i++) {
        $tmp = '';
        if ($i % 3 === 0) {
            $tmp .= 'Fizz';
        }
        if ($i % 5 === 0) {
            $tmp .= 'Buzz';
        }
        $str .= ($tmp !== '') ? $tmp : (string) $i;
    }

    return $str;
}
