MergeForeachPush <p>Groups indices by size, chunks them, then flattens all chunks using <code>array_merge()</code>. <pre><code>&lt;?php

    /**
     * @param array&lt;int, int&gt; $input
     * @return list&lt;list&lt;int&gt;&gt;
     */
    public static function viaMerge(array $input): array
    {
        $char = [];
        $result = [];
        foreach ($input as $key =&gt; $value) {
            $char[$value][] = $key;
        }
        foreach ($char as $size =&gt; $arr) {
            if ($size &lt;= 0) {
                continue;
            }
            $result[] = array_chunk($arr, $size);
        }
        return array_merge(...$result);
    }
</code></pre></p> <p>Groups indices by size, chunks them, then flattens with a nested <code>foreach</code>. <pre><code>&lt;?php

    /**
     * @param array&lt;int, int&gt; $input
     * @return list&lt;list&lt;int&gt;&gt;
     */
    public static function viaForeach(array $input): array
    {
        $char = [];
        $result = [];
        foreach ($input as $key =&gt; $value) {
            $char[$value][] = $key;
        }
        foreach ($char as $size =&gt; $arr) {
            if ($size &lt;= 0) {
                continue;
            }
            foreach (array_chunk($arr, $size) as $chunk) {
                $result[] = $chunk;
            }
        }
        return $result;
    }
</code></pre></p> <p>Groups indices by size, chunks them, then flattens using <code>array_push()</code> with spread. <pre><code>&lt;?php

    /**
     * @param array&lt;int, int&gt; $input
     * @return list&lt;list&lt;int&gt;&gt;
     */
    public static function viaPush(array $input): array
    {
        $char = [];
        $result = [];
        foreach ($input as $key =&gt; $value) {
            $char[$value][] = $key;
        }
        foreach ($char as $size =&gt; $arr) {
            if ($size &lt;= 0) {
                continue;
            }
            array_push($result, ...array_chunk($arr, $size));
        }
        return $result;
    }
</code></pre></p>

