declare(strict_types=1);

namespace Katas\IntegersToRoman;

final class IntegersToRoman
{
    public static function toRoman(int $input): string
    {
        $letters = [
            1000 =&gt; 'M',
            900  =&gt; 'CM',
            500  =&gt; 'D',
            400  =&gt; 'CD',
            100  =&gt; 'C',
            90   =&gt; 'XC',
            50   =&gt; 'L',
            40   =&gt; 'XL',
            10   =&gt; 'X',
            9    =&gt; 'IX',
            5    =&gt; 'V',
            4    =&gt; 'IV',
            1    =&gt; 'I',
        ];
        $romanNumber = '';

        foreach ($letters as $limit =&gt; $value) {
            while ($limit &lt;= $input) {
                $romanNumber .= $value;
                $input -= $limit;
            }
        }
        return $romanNumber;
    }
}
