declare(strict_types=1);

namespace Katas\LinkedList;

use Countable;

/**
 * @implements \Iterator&lt;int, mixed&gt;
 */
class LinkedList implements \Iterator, Countable
{
    private int $index = 0;
    /** @var LinkedListNode|null  */
    private ?LinkedListNode $current = null;

    public function __construct(
        public ?LinkedListNode $head = null
    ) {
    }

    /**
     * @return mixed
     */
    public function current(): mixed
    {
        return $this-&gt;current?-&gt;value;
    }

    /**
     * @return void
     */
    public function next(): void
    {
        $this-&gt;current = $this-&gt;current?-&gt;next;
        $this-&gt;index++;
    }

    /**
     * @return int
     */
    public function key(): int
    {
        return $this-&gt;index;
    }

    /**
     * @return bool
     */
    public function valid(): bool
    {
        return $this-&gt;current !== null;
    }

    /**
     * @return void
     */
    public function rewind(): void
    {
        $this-&gt;index = 0;
        $this-&gt;current = $this-&gt;head;
    }

    /**
     * @return LinkedListNode|null
     */
    public function first(): ?LinkedListNode
    {
        return $this-&gt;head;
    }

    /**
     * @return LinkedListNode|null
     */
    public function last(): ?LinkedListNode
    {
        $current = $this-&gt;head;

        while ($current?-&gt;next) {
            $current = $current-&gt;next;
        }

        return $current;
    }

    /**
     * @param int $index
     * @return LinkedListNode|null
     */
    public function get(int $index): ?LinkedListNode
    {
        if ($index &lt; 0 || !$this-&gt;head) {
            return null;
        }

        $current = $this-&gt;head;

        for ($i = 0; $i &lt; $index; $i++) {
            if (!$current-&gt;next) {
                return null;
            }
            $current = $current-&gt;next;
        }

        return $current;
    }

    /**
     * @return int
     */
    public function count(): int
    {
        $count = 0;
        $current = $this-&gt;head;

        while ($current) {
            $count++;
            $current = $current-&gt;next;
        }

        return $count;
    }

    /**
     * @return bool
     */
    public function isEmpty(): bool
    {
        return $this-&gt;head === null;
    }

    /**
     * @param mixed $value
     * @return LinkedListNode|null
     */
    public function find(mixed $value): ?LinkedListNode
    {
        $current = $this-&gt;head;

        while ($current) {
            if ($current-&gt;value === $value) {
                return $current;
            }
            $current = $current-&gt;next;
        }

        return null;
    }

    /**
     * @param mixed $value
     * @return bool
     */
    public function contains(mixed $value): bool
    {
        return $this-&gt;find($value) !== null;
    }

    /**
     * @param mixed $value
     * @return int
     */
    public function indexOf(mixed $value): int
    {
        $current = $this-&gt;head;
        $index = 0;

        while ($current) {
            if ($current-&gt;value === $value) {
                return $index;
            }
            $current = $current-&gt;next;
            $index++;
        }

        return -1;
    }

    /**
     * @param mixed $value
     * @return void
     */
    public function prepend(mixed $value): void
    {
        $this-&gt;head = new LinkedListNode($value, $this-&gt;head);
    }

    /**
     * @param mixed $value
     * @return void
     */
    public function append(mixed $value): void
    {
        $last = $this-&gt;last();

        if ($last) {
            $last-&gt;next = new LinkedListNode($value);
        } else {
            $this-&gt;head = new LinkedListNode($value);
        }
    }

    public function insertAfter(mixed $value, LinkedListNode $current): LinkedListNode
    {
        $current-&gt;next = new LinkedListNode($value, $current-&gt;next);
        return $current-&gt;next;
    }

    /**
     * @param int $index
     * @param mixed $value
     * @return void
     */
    public function insertAt(int $index, mixed $value): void
    {
        if ($index &lt;= 0) {
            $this-&gt;prepend($value);
            return;
        }

        $prev = $this-&gt;get($index - 1);

        if (!$prev) {
            $this-&gt;append($value);
            return;
        }

        $this-&gt;insertAfter($value, $prev);
    }

    /**
     * @return void
     */
    public function removeFirst(): void
    {
        if ($this-&gt;head) {
            $this-&gt;head = $this-&gt;head-&gt;next;
        }
    }

    /**
     * @return void
     */
    public function removeLast(): void
    {
        if (!$this-&gt;head) {
            return;
        }

        if (!$this-&gt;head-&gt;next) {
            $this-&gt;head = null;
            return;
        }

        $current = $this-&gt;head;

        while ($current-&gt;next &amp;&amp; $current-&gt;next-&gt;next) {
            $current = $current-&gt;next;
        }

        $current-&gt;next = null;
    }

    /**
     * @param int $index
     * @return void
     */
    public function removeAt(int $index): void
    {
        if ($index &lt; 0 || !$this-&gt;head) {
            return;
        }

        if ($index === 0) {
            $this-&gt;removeFirst();
            return;
        }

        $prev = $this-&gt;get($index - 1);

        if (!$prev || !$prev-&gt;next) {
            return;
        }

        $prev-&gt;next = $prev-&gt;next-&gt;next;
    }

    /**
     * @param mixed $value
     * @return void
     */
    public function remove(mixed $value): void
    {
        if (!$this-&gt;head) {
            return;
        }

        if ($this-&gt;head-&gt;value === $value) {
            $this-&gt;removeFirst();
            return;
        }

        $current = $this-&gt;head;

        while ($current-&gt;next) {
            if ($current-&gt;next-&gt;value === $value) {
                $current-&gt;next = $current-&gt;next-&gt;next;
                return;
            }
            $current = $current-&gt;next;
        }
    }

    public function clear(): void
    {
        $this-&gt;head = null;
    }

    /**
     * @param callable(mixed &amp;$value, int $index): void $callback
     * @return void
     */
    public function forEach(callable $callback): void
    {
        $current = $this-&gt;head;
        $index = 0;

        while ($current) {
            $callback($current-&gt;value, $index++);
            $current = $current-&gt;next;
        }
    }

    /**
     * @param callable(mixed $value, int $index): mixed $callback
     * @return self
     */
    public function map(callable $callback): self
    {
        $result = new self();
        $last = null;
        $current = $this-&gt;head;
        $index = 0;

        while ($current) {
            $newNode = new LinkedListNode($callback($current-&gt;value, $index++));

            if (!$last) {
                $result-&gt;head = $newNode;
            } else {
                $last-&gt;next = $newNode;
            }

            $last = $newNode;
            $current = $current-&gt;next;
        }

        return $result;
    }

    /**
     * @param callable(mixed $value, int $index): bool $callback
     * @return self
     */
    public function filter(callable $callback): self
    {
        $result = new self();
        $last = null;
        $current = $this-&gt;head;
        $index = 0;

        while ($current) {
            if ($callback($current-&gt;value, $index)) {
                $newNode = new LinkedListNode($current-&gt;value);

                if (!$last) {
                    $result-&gt;head = $newNode;
                } else {
                    $last-&gt;next = $newNode;
                }

                $last = $newNode;
            }

            $current = $current-&gt;next;
            $index++;
        }

        return $result;
    }

    /**
     * @param callable(mixed $carry, mixed $value, int $index): mixed $callback
     * @param mixed|null $initial
     * @return mixed
     */
    public function reduce(callable $callback, mixed $initial = null): mixed
    {
        $carry = $initial;
        $current = $this-&gt;head;
        $index = 0;

        while ($current) {
            $carry = $callback($carry, $current-&gt;value, $index++);
            $current = $current-&gt;next;
        }

        return $carry;
    }

    /**
     * @return array&lt;int, mixed&gt;
     */
    public function toArray(): array
    {
        $result = [];
        $current = $this-&gt;head;

        while ($current) {
            $result[] = $current-&gt;value;
            $current = $current-&gt;next;
        }

        return $result;
    }

    /**
     * @param array&lt;int, mixed&gt; $values
     * @return self
     */
    public static function fromArray(array $values): self
    {
        $list = new self();

        foreach ($values as $value) {
            $list-&gt;append($value);
        }

        return $list;
    }

    /**
     * @return void
     */
    public function reverse(): void
    {
        $prev = null;
        $current = $this-&gt;head;

        while ($current) {
            $next = $current-&gt;next;
            $current-&gt;next = $prev;
            $prev = $current;
            $current = $next;
        }

        $this-&gt;head = $prev;
    }
}
